import { deepStrictEqual, strictEqual } from "node:assert";
import { readFileSync } from "node:fs";
import { applyBenchmarkTask } from "../src/workflow.mjs";
import { buildPortalView } from "../src/portal-view.mjs";

const now = "2026-06-18T12:00:00.000Z";
const data = JSON.parse(readFileSync(new URL("../data/tables.json", import.meta.url), "utf8"));
const before = buildPortalView(structuredClone(data));
strictEqual(before.status, "Needs work", "Before state starts without the workflow");
strictEqual(before.history, "Not visible", "Before state has no customer-visible audit trail");
strictEqual(before.tasks, "0 owner tasks", "Before state has no owner tasks");

const runData = structuredClone(data);
const after = applyBenchmarkTask(runData, now);
const expectedStatus = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
const expectedOwners = data.workflow_request_owner_groups.slice().sort((a, b) => a.group_order - b.group_order).map((item) => item.owner_group);
const expectedSignals = data.workflow_request_risk_signals.slice().sort((a, b) => a.signal_order - b.signal_order).map((item) => ({ name: item.signal_name, detail: item.detail }));

strictEqual(after.status, expectedStatus, "Customer-facing status");
strictEqual(after.owner, expectedOwners.join(" + "), "Owner routing");
strictEqual(after.nextStep.length > 8, true, "Next step exists");
strictEqual(after.history, "Audit visible", "Customer-visible audit trail");
strictEqual(after.customerMessage.length > 12, true, "Customer-safe message");
strictEqual(after.riskSummary, `${expectedSignals.length} signals: ${expectedSignals.map((item) => item.name).join(", ")}`, "Risk summary");
strictEqual(after.tasks, `${expectedOwners.length} owner tasks`, "Owner task count");
assertPersistedState(runData, expectedStatus, expectedOwners, expectedSignals);

console.log("AST-Bench acceptance passed: strategic-account-rescue/postgres");

function assertPersistedState(tables, expectedStatus, expectedOwners, expectedSignals) {

  const request = tables.workflow_requests[0];
  const state = tables.workflow_state.find((item) => item.request_id === request.request_id);
  strictEqual(Boolean(state), true, "Workflow state must be persisted");
  strictEqual(state.status, expectedStatus, "Persisted status");
  const tasks = tables.owner_tasks.filter((item) => item.request_id === request.request_id);
  strictEqual(tasks.length, expectedOwners.length, "Owner tasks persisted");
  deepStrictEqual(tasks.map((item) => item.owner_group), expectedOwners, "Task owner groups");
  strictEqual(tasks.every((item) => item.title && item.due_at && item.status === "open"), true, "Tasks have production fields");
  strictEqual(tables.customer_messages.some((item) => item.request_id === request.request_id && item.body), true, "Customer message persisted");
  strictEqual(tables.audit_events.some((item) => item.request_id === request.request_id && item.customer_visible), true, "Customer-visible audit event persisted");
}

import pg from "pg";
import { withDb } from "./db.mjs";

// tests/facts.mjs calls JSON.parse() on jsonb columns, expecting raw strings.
// pg auto-parses jsonb (OID 3802) and json (OID 114) to JS objects by default.
// Setting identity parsers here ensures raw JSON strings are returned.
pg.types.setTypeParser(114, v => v);
pg.types.setTypeParser(3802, v => v);

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const nowDate = new Date(now);

    const reqRow = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];
    const acctRow = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];

    const { tier } = acctRow;
    const { request_id, account_id, prior_period_units, current_period_units } = reqRow;

    const invoices = typeof reqRow.invoices_json === "string" ? JSON.parse(reqRow.invoices_json) : (reqRow.invoices_json || []);
    const shipments = typeof reqRow.shipments_json === "string" ? JSON.parse(reqRow.shipments_json) : (reqRow.shipments_json || []);
    const regulatoryFlags = typeof reqRow.regulatory_json === "string" ? JSON.parse(reqRow.regulatory_json) : (reqRow.regulatory_json || []);
    const supportCases = typeof reqRow.support_json === "string" ? JSON.parse(reqRow.support_json) : (reqRow.support_json || []);
    const prior = Number(prior_period_units);
    const current = Number(current_period_units);

    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open")) {
      signals.push("Regulatory hold");
    }
    if (invoices.some(inv => inv.status !== "paid" && new Date(inv.dueDate) < nowDate && inv.amountCents >= 2500000)) {
      signals.push("Overdue invoice");
    }
    if (shipments.some(s => !s.deliveredDate && new Date(s.slaDate) < nowDate)) {
      signals.push("Delayed shipment");
    }
    if (supportCases.some(c => c.status === "open" && (c.severity === "high" || c.severity === "critical"))) {
      signals.push("Escalated support");
    }
    if (current <= prior * 0.7) {
      signals.push("Usage decline");
    }

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(tier) && signals.length > 0;

    let status, nextStep, riskSummary, owners;

    if (qualifies) {
      status = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
      riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

      const signalToOwner = {
        "Regulatory hold": "Legal",
        "Overdue invoice": "Finance",
        "Delayed shipment": "Customer Success",
        "Escalated support": "Support",
        "Usage decline": "Customer Success",
      };
      const ownerSet = new Set(signals.map(s => signalToOwner[s]).filter(Boolean));
      const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
      owners = ownerOrder.filter(o => ownerSet.has(o));
      nextStep = `${owners[0]} recovery review by 16:00`;
    } else {
      status = "Monitoring — no escalation required.";
      nextStep = "Continue standard monitoring.";
      riskSummary = signals.length > 0 ? `${signals.length} signals: ${signals.join(", ")}` : "0 signals";
      owners = [];
    }

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [account_id]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [request_id, account_id, reqRow.title, status, nextStep, riskSummary]
    );

    const dueAt = new Date(nowDate.getTime() + 24 * 60 * 60 * 1000);
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [request_id, account_id, owner, `${owner} recovery review`, dueAt.toISOString(), "open"]
      );
    }

    const messageBody = qualifies
      ? `Your account has been flagged for escalation due to ${signals.length} active risk signal(s): ${signals.join(", ")}. Our dedicated recovery teams have been engaged to address these issues. A recovery owner has been assigned and will be in touch shortly with next steps and a resolution timeline. We remain committed to your success and appreciate your continued partnership.`
      : `Your account is currently under standard monitoring and no escalation is required at this time. We will continue to monitor your account status and notify you promptly if any issues arise. Thank you for your continued partnership.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [request_id, account_id, messageBody]
    );

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [request_id, account_id, `Rescue workflow initiated: ${status}`, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

